fn compute_centroid(vectors: &[&Vec<f32>]) -> Vec<f32> {
    let dim = vectors[0].len();
    let mut centroid = vec![0.0f32; dim];
    for v in vectors {
        for (j, val) in v.iter().enumerate() {
            centroid[j] += val;
        }
    }
    let n = vectors.len() as f32;
    centroid.iter_mut().for_each(|x| *x /= n);
    centroid
